INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('eupho', 'European Physics Olympiad', 'A relatively new and highly interesting olympiad', '🇪🇺', 'Regional', 0, 'A highly interesting olympiad with short but insightful problems, though some may call them contrived. It has a relatively short history, with the first edition in 2017. In many ways, this olympiad follows the IPhO statutes even better than IPhO itself, as the problems requires physical insight and you rarely need to rush for time. Inspired by the [Eötvös Competition](/olympiads/eotvos).
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('ipho', 'International Physics Olympiad', 'The most well-known physics olympiad, attracting participants from 90+ countries', '', 'International', 1, 'The International Physics Olympiad (IPhO) is the most famous physics competition for secondary school students. The main aim of IPhO is to test the highest level of knowledge, critical thinking, problem solving, proper practices of presentation and analysis, and hands-on skills in theoretical and experimental physics. The IPhO is organized annually in different countries as a 9-10 day competition where national teams comprising a maximum of five of their best physics students and two team leaders participate.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('apho', 'Asian Physics Olympiad', 'The Asian version of IPhO, often used by countries to select their IPhO teams.', '', 'Regional', 2, 'The Asian Physics Olympiad (APhO), initiated in the year of 2000 by Indonesia, is an annual international physics competition devoted to secondary school students in Asia. It is usually held in late April or early May, and more than 20 countries participate in it regularly. It is very similar in style and process to [IPhO](/olympiads/ipho), except each participating country can send 8 contestants at most instead of 5 in IPhO. Hence, it is often used by countries as a selection test to decide who goes to IPhO.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('nbpho', 'Nordic-Baltic Physics Olympiad', 'A regional physics olympiad for students from the Nordic and Baltic countries, including Estonia, Finland, Sweden and Latvia.', '🇪🇪 🇫🇮 🇸🇪 🇱🇻', 'Regional', 3, 'The Nordic-Baltic Physics Olympiad (NBPhO) is a regional physics olympiad for students in Estonia, Finland, Sweden and Latvia. It serves as a selection test for the International Physics Olympiad (IPhO) and is held annually in the spring. The problems tend to be highly insightful, reminiscent of [EuPhO](/olympiads/eupho), but easier and more guided. Check out the [official website](https://nbpho.ee/) and [errata](https://stefanivanov.site/teaching/errata.pdf) for more information.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('usapho', 'USA Physics Olympiad', 'Second round of selection for the US Physics Team', '🇺🇸', 'National', 4, 'This is the second round of selection for the U.S. Physics Team. You are given 90 minutes for each part (A and B) of the competition, with a short break in between. For more information, see [the official website](https://www.aapt.org/physicsteam/).
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('usatst', 'USA Team Selection Test', 'Final round of selection for the US Physics Team', '🇺🇸', 'National', 5, 'The final round of selection for the U.S. IPhO team, held during the Physics Team camp in Maryland. These are the only publicly available exams.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('eotvos', 'Eötvös Competition', 'One of the oldest high school physics olympiads.', '🇭🇺', 'National', 6, 'The Hungarian Eötvös competition is perhaps the oldest high school physics competition in the world, with over a century of competition since its first edition in 1894. Each olympiad lasts for 5 hours and has 3 short problems. The competition tests creativity and problem-solving skills not found in most modern physics olympiads, and inspired the [European Physics Olympiad](/olympiads/eupho). Many of the old problems (pre-2018) have made their way into 200 Puzzling Physics Problems and its sequel. Note that it is an open-book exam, so you are expected to have a standard constants sheet with you (e.g [this](https://sgphysicsleague.org/data_sheet.pdf)). In my translations, I will make a note when it requires information that isn''t in a standard constants sheet.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('pcup', 'Physics Cup', 'The most difficult high school physics olympiad', '🏆', 'Open', 7, 'Coming soon! For now, see a pdf version of the problems [here](https://github.com/m-spitfire/phys_cup). Thanks to spitfire for collating this.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('aupho', 'Australian Physics Olympiad', 'First round of selection for the Australian team at the IPhO.', '🇦🇺', 'National', 8, '[Errata](https://www.physicsforums.com/insights/corrections-to-the-australian-physics-olympiad-questions-and-solutions/)
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('spot', 'Singapore IPhO/APhO TST', 'Selection test for the Singapore team at IPhO and APhO.', '🇸🇬', 'National', 9, 'The Singapore Team Selection Test for IPhO, APhO and INSO. As of now, the top 5 participants go for IPhO, the next 8 go for APhO and recently the next 4 go to INSO (the nuclear science olympiad). It is decent practice for IPhO, being much more guided, but the time pressure is significantly higher too. Difficulty and time pressure varies wildly over the years, though.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('cpho-f', 'Chinese Physics Olympiad (Finals)', 'Third phase of selection for the Chinese IPhO team', '🇨🇳', 'National', 10, 'This is the third round of selection for the Chinese IPhO team. This round of selection is followed by the team selection test, which is confidential and often contains problems from higher physics (analytical mechanics, advanced electrodynamics, quantum mechanics and statistical mechanics). Many of the files here are Word documents, but I will be converting them to pdfs in the near future for easier web viewing.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('izho', 'International Zhautykov Olympiad', 'A multi-subject olympiad comprising of Mathematics, Physics and Computing', '🇰🇿', 'International', 11, 'The International Zhautykov Olympiad (IZhO) is an annual multi-subject olympiad comprising of Mathematics, Physics and Computing. It is held in Kazakhstan and is named after the Kazakh mathematician and educator, Ilyas Zhautykov. The IZhO attracts top high school students from around the world to compete in challenging problems across these three subjects. The competition aims to foster international cooperation and promote excellence in science and mathematics among young students. 
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('inpho', 'Indian National Physics Olympiad', 'Second round of selection for the Indian IPhO team.', '🇮🇳', 'National', 12, 'The Indian National Physics Olympiad (InPhO) is the second round of selection for the Indian IPhO team. I thank [Ashmit Dutta](https://github.com/aedutta) for writing the detailed solutions for 2011 and 2012.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('sjpo', 'Singapore Junior Physics Olympiad', 'A well-set national olympiad for secondary school students', '🇸🇬', 'National', 13, 'The Singapore Junior Physics Olympiad (SJPO) is an algebra-based olympiad for secondary school students that assumes no knowledge of calculus. It is quite well-set, with many thought-provoking problems. The time pressure can be quite high, with olympiadants having to solve 50 multiple-choice questions in 2 hours. The questions here are from the general round. In 2024 there was some technical issue which caused the competition to have to be taken again, so there are two versions of the problems. SJPO 2020 is pointless as it was a compilation of past year problems, so I won''t include it here. There were some technical issues in 2021 so it didn''t really work out. I''ve tried my best to find as many papers as I can, but if you have a paper or its solutions that isn''t here, do let me know. I thank the folks at [PD Stem Education](https://www.pd-stem.com/) for making solutions to 2022 and 2024, found [here](https://drive.google.com/drive/folders/18B5GEA6r5dmef2QbzQteKk3EKrXxuU05).
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('spho', 'Singapore Physics Olympiad', 'The first round of the selection for IPhO in Singapore', '🇸🇬', 'National', 14, 'The Singapore Physics Olympiad (SPhO) is the first round of the selection process for the International Physics Olympiad (IPhO) in Singapore. It is arguably easier than SJPO. I only recommend doing past year papers if you are preparing specifically for this, but even then you should only do 1 or 2 to get a feeling of how the paper is like, and spend the rest of your time learning physics properly. Most of the problems are straightforward, but intentionally niche or vague to make it artifically difficult. For example, in 2024, you needed to know what a Hohmann transfer was. If you did, it becomes a trivial application of the vis-viva equation, but impossible if you didn''t. Just like SJPO, it also tends to have quite a lot of mistakes, so don''t go insane if your answer differs from theirs. Generally, to do well, you just need to have superficial knowledge of everything in the syllabus, as the problems rarely go beyond the absolute basics of what you learn. 
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('bpho-r1', 'British Physics Olympiad Round 1', 'The first round of the British Physics Olympiad, a physics competition for high school students in the UK.', '🇬🇧', 'National', 15, NULL, NULL, '{"problems":{"label":"Problems"},"problemsEn":{"label":"Problems (EN)"},"theory":{"label":"Theory"},"experiment":{"label":"Experiment"},"solutions":{"label":"Solutions"},"answerSheet":{"label":"Answer Sheets"},"theorySolutions":{"label":"Theory Solutions"},"experimentSolutions":{"label":"Experiment Solutions"},"theoryMarkingScheme":{"label":"Theory Marking Scheme"},"experimentMarkingScheme":{"label":"Experiment Marking Scheme"},"theoryInstructions":{"label":"Theory General Instructions"},"experimentalInstructions":{"label":"Experiment General Instructions"},"experimentalFiles":{"label":"Experimental Files"},"experimentalPresentation":{"label":"Experimental Presentation"},"report":{"label":"Report"},"results":{"label":"Results"},"minutes":{"label":"Minutes"},"proceedings":{"label":"Proceedings"},"comments":{"label":"Comments"},"FirstSection":{"label":"Section 1"},"SecondSection":{"label":"Section 2"},"FirstSectionSolutions":{"label":"Solutions (Section 1)"},"SecondSectionSolutions":{"label":"Solutions (Section 2)"}}', '{"problem":{"label":"Problem"},"problemEn":{"label":"Problem (EN)"},"solution":{"label":"Solution"},"answerSheet":{"label":"Answer Sheet"},"markingScheme":{"label":"Marking Scheme"},"presentation":{"label":"Presentation"}}');
