INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('kphc', 'Korean Middle School Physics Competition', 'A national physics olympiad for middle-school students', '🇰🇷', 'National', 17, 'The Korean Physics Middle-School Olympiad (KPhC) serves individuals targeting admission into specialized Science High Schools. The examination consists of 30 multiple-choice questions covering a broad range of classical and modern physics. On average, mechanics constitutes approximately 45% of the exam, followed by electromagnetism at 25%, waves and optics at 20%, and thermodynamics and modern physics accounting for roughly 5% each. The test is "multiple-selection", where certain questions may require selecting up to four correct options or identifying a single specific correct statement among several complex distractors.
INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('rupho-w', 'Russian Team Selection Test (W)', 'Preparation for 10th graders in Russia for the TST', '🇷🇺', 'National', 18, 'A IPhO-style competition for 10th graders in Russia to prepare for the team selection test (X and Y).
