INSERT INTO olympiads (id, name, summary, icon, tag, display_order, description_md, description_html, year_file_types, problem_file_types) VALUES ('upho', 'All-Ukrainian Physics Olympiad', 'Annual national physics olympiad for Ukrainian secondary school students.', '🇺🇦', 'National', 21, 'The All-Ukrainian Physics Olympiad (UPhO) is a national competition for secondary school students in Ukraine, held annually in different cities. The competition consists of theoretical and experimental rounds across multiple grades.
