', '<p>The International Physics Olympiad (IPhO) is the most famous physics competition for secondary school students. The main aim of IPhO is to test the highest level of knowledge, critical thinking, problem solving, proper practices of presentation and analysis, and hands-on skills in theoretical and experimental physics. The IPhO is organized annually in different countries as a 9-10 day competition where national teams comprising a maximum of five of their best physics students and two team leaders participate.</p>
<p>The files here have been collected from various sources, including the official website, national team websites, and personal connections. If you have any missing files or corrections, please let us know!</p>
', '{"problems":{"label":"Problems"},"problemsEn":{"label":"Problems (EN)"},"theory":{"label":"Theory"},"experiment":{"label":"Experiment"},"solutions":{"label":"Solutions"},"answerSheet":{"label":"Answer Sheets"},"theorySolutions":{"label":"Theory Solutions"},"experimentSolutions":{"label":"Experiment Solutions"},"theoryMarkingScheme":{"label":"Theory Marking Scheme"},"experimentMarkingScheme":{"label":"Experiment Marking Scheme"},"theoryInstructions":{"label":"Theory General Instructions"},"experimentalInstructions":{"label":"Experiment General Instructions"},"experimentalFiles":{"label":"Experimental Files"},"experimentalPresentation":{"label":"Experimental Presentation"},"report":{"label":"Report"},"results":{"label":"Results"},"minutes":{"label":"Minutes"},"proceedings":{"label":"Proceedings"},"comments":{"label":"Comments"},"extraMinutes":{"label":"Extraordinary Minutes"}}', '{"problem":{"label":"Problem"},"problemEn":{"label":"Problem (EN)"},"solution":{"label":"Solution"},"answerSheet":{"label":"Answer Sheet"},"markingScheme":{"label":"Marking Scheme"},"presentation":{"label":"Presentation"},"calibration":{"label":"Calibration"}}');

